var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"와아아! 안녕하세요! 이거 정말 방송에 나오는 건가요?!","JPN":"わ～～！　こんにちは！\\nこれ本当に配信されてるんですか！？","ENG":"Wow, hello! Is this really live right now?","TWN":"哇啊啊！大家好！這真的會在廣播裡播出嗎？！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"다, 당황하지 마랏! 베, 베테랑 병사는 총구와 카메라렌즈 따위에 흔들리지 않아!","JPN":"あ、慌てるな！\\nべ、ベテランの兵士は銃口とカメラレンズの前で、戸惑ったりしないものだ！","ENG":"D-don't be nervous! V-veteran soldiers shouldn't be afraid of enemies' guns, or the camera!","TWN":"別、別慌！老兵可不會害怕區區槍口和攝像頭！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"하하! 그러지 말고 손이라도 흔들어 보라니까?","JPN":"そんなカチカチにならなくて大丈夫だよ？\\n手を振ってみようよ！","ENG":"Hah hah! Don't be like that. Why don't you wave your hand at it?","TWN":"哈哈！別這樣啦，和大家招招手怎麼樣？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"예전부터 TV에 나오고 싶어 했잖아.","JPN":"前からTVに出たがってたでしょ～？","ENG":"You've always wanted to be on TV.","TWN":"你不是一直想上電視嘛。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그, 그건 빛나는 전공을 세운 후 훈장수여식에 나오고 싶다는 뜻이었다, 대장!","JPN":"そ、それは、輝かしい戦功を立てた後、勲章を授与される時の話だ、隊長！","ENG":"T-to receive a medal of merit for my brilliant service, Captain!","TWN":"我、我是說立下光榮戰功後，出現在勳章授予儀式上，隊長！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"귀여운 아이들이군요. 이런 작은 방송 카메라 앞에서도 긴장하다니.","JPN":"かわいい子たちですわね。こんな小さなカメラの前でも緊張するなんて。","ENG":"You guys are cute. You get nervous before such a tiny camera like this.","TWN":"真是群可愛的孩子，在這種小廣播的攝像機前也會緊張啊。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"와, 무지 예쁜 언니다!","JPN":"わあ、美人なお姉さん！","ENG":"Whoa, you're so pretty!","TWN":"哇，好漂亮的姐姐！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"저희 방송은 처음이거든요. 언니는 괜찮아요?","JPN":"僕たち、撮影されるの初めてなんです。お姉さんは平気なんですか？","ENG":"We've never been on a live show before. Aren't you nervous?","TWN":"我們是第一次參加直播嘛，姐姐不會緊張嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"물론 그럴 수 밖에요.","JPN":"もちろんですわ。","ENG":"Absolutely not.","TWN":"當然啦。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"전 어렸을 때부터 이골이 날 정도로 남들의 주목을 받아왔거든요.","JPN":"私は幼い頃から、いやと言うほど周りから注目されてきましたので。","ENG":"I've always been the centre of attention since I was young.","TWN":"我從小時候起就一直受到別人的注目，幾乎都習慣啦。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그럼 언니도 연예인이에요? 어쩐지!","JPN":"それじゃあ、お姉さんも芸能人なんですか？　やっぱり！","ENG":"Are you a celebrity? I knew it!","TWN":"那姐姐也是藝人嘍？怪不得！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그런 건 아니지만...... 어떤 영감님들에겐 그 비슷한 취급을 받고 있긴 하죠.","JPN":"そういうわけではありませんが……\\n一部の方々には、似たような扱いを受けていますわ。","ENG":"Not exactly, but in a way I am, among some gaffers.","TWN":"也不是……不過對一些老爺子來說也差不多吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"저어...... 인사가 끝났으면 자기소개를 시작해도 될까요?","JPN":"あのう……挨拶が終わったようですので、\\n自己紹介をお願いできますか？","ENG":"Erm, if you're finished saying hello to each other, mind introducing yourselves to our viewers?","TWN":"那個……打過招呼的話可以開始自我介紹了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 저요! 저요! 저부터 할래요!","JPN":"あ、僕から自己紹介させてください！","ENG":"Ooh, me! Me! Let me go first!","TWN":"啊，我！我！從我開始吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"관리국 카운터 아카데미 중등부에 다니고 있는 양하림입니다!","JPN":"管理局のカウンターアカデミー、中等部のホシノ・ウサギです！","ENG":"My name is Yang Harim, and I'm in the Administration's Junior High Academy.","TWN":"我是管理局制裁者學院初中部的楊夏琳！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"여기에 와서 채집을 도와드리면 수행평가 점수에 반영된다고 해서 왔어요!","JPN":"ここで採集のお手伝いをすれば成績に反映されるということなので、\\n手伝いに来ました！","ENG":"I came here to help harvest the fruit and get Performance Appraisal Points.","TWN":"我聽說，來這裡幫忙採集可以反映到個人評估分數裡，所以就過來了！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그리고 난 같은 곳에서 훈련을 받고 있는 한소림 병장이다.","JPN":"そして本官は、同じ所で訓練を受けている兵長、ハネダ・ミズキだ。","ENG":"I'm Han Sorim, sergeant in the same Academy as she.","TWN":"她是和我在一個地方接受訓練的蕭林兵長。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"병장이요? 소림양은 그...... 군인이라기엔 너무 어리지 않나요?","JPN":"兵長ですか？　ミズキさんは、その……\\n軍人というには、年齢的に無理があると思うのですが……","ENG":"Sergeant? Sorim, but aren't you... a little bit too young to be a soldier?","TWN":"兵長？說蕭林小姐，那個……是軍人的話會不會太年輕了？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"훗! 진정한 솔져를 가리는 기준은 나이 같은 게 아니다.","JPN":"ふっ！　本当のソルジャーの基準は年齢などではない。","ENG":"Hah! Age doesn't matter when it comes to soldiers.","TWN":"哼！選拔真正士兵的基準可不是年齡之類的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"얼마나 많은 실전경험을 거쳐 나왔느냐, 그것이 솔져의 자질을 가리는 척도라 할 수 있지.","JPN":"どれだけ多くの実戦を経てきたか。\\nそれが、ソルジャーの才能を見極める基準だ。","ENG":"What matters is their field experience.","TWN":"一個士兵資質如何得看他有多少實戰經驗才對。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그런 의미에서, 난 어린 시절부터 스미스 병장과 함께 수많은 혹독한 시련을 거쳐온 베테랑인 것이다.","JPN":"そういう意味で、本官は幼い頃からスミス兵長と\\n数々の過酷な訓練を受けたベテランである。","ENG":"In that sense, I'm a veteran who's overcome countless hardships with Sergeant Smith since he was young.","TWN":"從這點上看，我從小就和史密斯兵長一起經歷過無數殘酷試煉，算是老兵了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"스미스 병장......? 그 사람도 한소림 병장과 비슷한 또래인가요?","JPN":"スミス兵長……？　その方も、ハネダ兵長と年齢が近いんですか？","ENG":"Sergeant Smith? Is he the same age as you, Sergeant Han?","TWN":"史密斯兵長？這位也是蕭林兵長的同輩嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그렇다. 스미스는 하림 대장을 제외하면, 내가 등을 믿고 맡길 수 있는 유일한 전우라 할 수 있지.","JPN":"うむ。ホシノ隊長を除けば、スミスは本官が背中を預けられる、唯一の戦友だ。","ENG":"That's right. Smith is the only comrade I can trust with my life, except for Captain Harim.","TWN":"是的。不算夏琳隊長的話，史密斯可以說是唯一一個能讓我放心託付後背的戰友了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"지금은 기숙사...... 아니 내무반을 철통같이 경비 중이기 때문에 함께 오지 못했다만.","JPN":"今は寮……いや、内務班の警備を任されているため、\\n一緒に来ることはできなかった。","ENG":"He couldn't come with me because he has to keep watch over my dorm—I mean, barracks.","TWN":"現在他在守衛宿舍……不，是守衛內務班，所以沒能一起來。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"......소림아. 스미스 병장은 지금 네 가방에 걸려 있어.","JPN":"……ミズキ。スミス兵長は、カバンについているよ？","ENG":"S-Sorim, Sergeant Smith is dangling from your bag right now.","TWN":"……蕭林啊，史密斯兵長現在正掛在你的包上。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"아앗! 스미스 병장, 허가도 없이 근무지를 이탈하다니!","JPN":"ああっ！　スミス兵長、許可もなく勤務地を抜け出すとは！","ENG":"What?! Sergeant Smith, you can't leave your post without a permission!","TWN":"啊啊！史密斯兵長，你未經允許就離開工作崗位了嗎！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"가방 뒤? 저기에 걸려 있는 건 토끼 인형 밖에 없는데요......?","JPN":"カバン？　カバンについてるのは、うさぎの人形だけですよ……？","ENG":"Dangling from her bag? There's only a rabbit doll dangling from her bag.","TWN":"包後面？那裡掛著的只有兔子玩偶啊……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"맞아요! 그 토끼인형 이름이 스미스 병장이에요.","JPN":"はい！　その人形の名前が、スミス兵長なんです。","ENG":"Yes, and that rabbit doll is called Sergeant Smith.","TWN":"對！這只兔子玩偶的名字叫做史密斯兵長。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"뭐라고, 스미스 병장?","JPN":"どうした、スミス兵長？","ENG":"Say again, Sergeant Smith?","TWN":"你說什麼，史密斯兵長？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"본관과 한시라도 떨어져있으면 불안해서 견디질 못하겠다고?","JPN":"不安だから、一瞬たりとも本官と離れたくないだと？","ENG":"You get anxious when you're away from me.","TWN":"就算只與本官分離一會兒也覺得不安，無法忍受？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그렇게까지 말한다면 어쩔 수 없군.","JPN":"そこまで言うなら仕方ない。","ENG":"If that's the case, then I have no choice.","TWN":"你都這麼說了那也沒辦法啦。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"하지만 그런 의존적인 태도는 군인으로서 실격이다.","JPN":"しかし、その本官に依存する態度は軍人としては失格だ。","ENG":"But soldiers shouldn't be so dependent on others.","TWN":"但你這依賴的態度作為軍人是失格的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"천천히 고쳐나가야만 한다, 솔저!","JPN":"徐々に直していくべきだ、ソルジャー！","ENG":"Try to rectify that, soldier!","TWN":"必須要慢慢改掉這點，士兵！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"하하, 네. 스미스 대원님도 저희와 함께 해주신다고 하니 든든하네요.","JPN":"ハハハ。はい、スミス兵長もご一緒してくださるようで頼もしいですね。","ENG":"Hah hah, okay. I'm glad that Sergeant Smith will be with us, too.","TWN":"哈哈，好的。史密斯隊員也一起來了，真是令人安心呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그리고 그쪽에 계신 분은......?","JPN":"あと、そちらの方は……","ENG":"And you over there, could you introduce yourself?","TWN":"然後這裡的這位是……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저는 엘리자베스라고 해요.","JPN":"私、エリザベスと申します。","ENG":"My name is Elizabeth.","TWN":"我叫伊莉莎白。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"홍차에 어울리는 아주 특별한 디저트를 구할 수 있다고 해서 자원했어요.","JPN":"紅茶に合う、とっておきのデザートが手に入るとお聞きして参りました。","ENG":"I volunteered so I could get the special dessert; I was told it beautifully complements black tea.","TWN":"我聽說能找到非常特殊的甜點搭配紅茶，所以來了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"케이크나 쿠키도 좋지만, 가끔은 별미를 찾아 돌아다니는 것도 꽤 즐겁답니다.","JPN":"ケーキやクッキーもいいですが、たまには珍味を探して回るのも楽しいので。","ENG":"Cake and cookies are good, but sometimes I like to look for special snacks.","TWN":"雖然蛋糕和曲奇也很好，但偶爾去找尋一些別有風味的甜點也很令人愉快。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"평범한 디저트들은 이제 질려서 말이죠.","JPN":"普通のデザートには飽きてしまいましたの。","ENG":"Actually, I'm tired of ordinary desserts.","TWN":"我現在已經厭倦普通的甜點了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"와, 엘리자베스 씨는 정말 용감하신 분 같아요.","JPN":"わあ、エリザベスさんはとても勇敢なんですね。","ENG":"Wow. Elizabeth. You're very brave.","TWN":"哇，看來伊莉莎白小姐真的很有勇氣呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"아무리 평범한 맛에 질렸다고 해도 이런 괴상......","JPN":"いくら普通の味に飽きたといっても、こんな変な……","ENG":"Even if I was tired of ordinary desserts,","TWN":"不管再怎麼厭倦普通的味道，像這種奇怪的……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"아니 특이한 음식을 먹으러 자원하시다니......","JPN":"いや、独特な物を食べるために、自分から申し出るなんて……","ENG":"I'd never volunteer for food so grotesque—sorry, peculiar.","TWN":"啊不，我是說奇特的食物，為了這種奇特的食物而來……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 잠시 실례하겠어요.","JPN":"あ、ちょっと失礼。","ENG":"Ah, excuse me.","TWN":"啊，失禮了，請稍等。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"엘리자베스 아가씨! 이번엔 또 어디로 가신 겁니까?!!","JPN":"エリザベスお嬢様！　どこにいらっしゃるんですか！！？","ENG":"Lady Elizabeth! Where did you go this time?","TWN":"伊莉莎白大小姐！您這次又要去哪裡啊？！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L20_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그 나이에 가출이라니, 제발 철 좀 드십쇼!","JPN":"その年で家出をするなんて、信じられません！","ENG":"Please, you're too old to run away from home!","TWN":"都這個年紀了還離家出走，拜託您稍微懂事一點吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"가문에 결재해야 할 서류가 얼마나 쌓여 있는지 아십니까?!","JPN":"お嬢様の確認が必要な書類が山積みなんです！","ENG":"There are many documents that require your signature!","TWN":"您知道家裡要批的檔攢了多少嗎？！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하하, 그런 소릴 한다고 돌아오실 거면 아가씨가 아니지.","JPN":"ははは。うちのお嬢様が、そんなことを言われて戻って来るわけないだろ。","ENG":"Hah hah hah. If she listened to you, she'd never have left in the first place.","TWN":"哈哈哈，要是這麼說了就乖乖回去的話小姐就不是小姐了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L23_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"기왕 도망치셨으니, 이 참에 스트레스나 좀 풀고 오시죠, 아가씨.","JPN":"せっかくですから思いっきり羽目を外してください、お嬢様。","ENG":"You're already there. You might as well let off some steam, My Lady.","TWN":"既然都已經逃跑了，就趁這次機會疏解一下壓力吧，小姐。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"이봐, 자네! 그걸 말이라고......!!","JPN":"おい！　何てことを……！！","ENG":"Hey! How could you say that?!","TWN":"喂，我說你！這也叫人話嗎……！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L28_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"뭐, 뭐였죠, 방금 그건?","JPN":"あ、あれ？　何ですか、今のは？","ENG":"Wh-what was that?","TWN":"什、什麼？剛才怎麼了？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"신경쓰지 마세요.","JPN":"お気になさらず。","ENG":"Don't worry.","TWN":"請不要在意。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그저 집안의 영감님들이 제 출장지 선별에 좀 엄격하신 편이라서요.","JPN":"うちのおじさま方は、出張先の選別に厳しいので。","ENG":"They're some old men at my house who are picky about where I go.","TWN":"只是家中的老爺子們對我選擇出差地點比較嚴格。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"혹시나 해서 묻는 거지만...... 가출하신 건 아니죠?","JPN":"念のため確認させていただきますが……\\n家出じゃないですよね？","ENG":"I'm just curious, but... you really didn't run away from home, did you?","TWN":"問一下……您不是離家出走吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"이건 관리국 후원을 받는 정규 방송이라서...... 미승인 참가자는 곤란한데요......","JPN":"これ、管理局がスポンサーの公式放送なので……\\n承認を受けてない参加者は困るんです……","ENG":"Our show is officially sponsored by the Administration. We can't have anyone on it who hasn't been approved.","TWN":"這是管理局贊助的正規廣播，所以……有未經許可的參加者我們會很困擾的……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 그 점에 대해서라면 걱정 않으셔도 된답니다.","JPN":"あら、その点ならご心配なく。","ENG":"Ah, you don't have to worry about that.","TWN":"啊，請不用擔心這個。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그, 그렇다면 다행이네요......","JPN":"そ、そういうことなら……","ENG":"I-I'm glad.","TWN":"那，那真是太好了……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"가문의 당주인 제가 혼자 여행 좀 다닌다고 해서 가출이 성립될 리가 없잖아요?","JPN":"ペンドラゴン家の当主である私が一人旅に出たところで、\\n家出になるわけがないでしょう？","ENG":"I'm the head of my house. Just because I'm traveling alone, it doesn't mean I ran away from home, does it?","TWN":"這是身為家主的我偶爾來一次的個人旅行罷了，不能算是離家出走吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"오히려 절 따라오지 못하는 가문이 낙오된 거라고 볼 수 있죠.","JPN":"むしろ、私について来られないペンドラゴン家の者たちがダメなだけですわ。","ENG":"It's their fault that they're unable to keep up with me.","TWN":"反而是家中非要跟來的人思想太落伍了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"......아, 네. 그렇군요. 합리적이네요.","JPN":"……あ、はい。そうですね。非常に合理的です。","ENG":"... Ah, I see. That's reasonable.","TWN":"……啊，對。是這樣啊。非常合理。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그런데 합류하기로 한 두 분이 아직 보이지 않아요.","JPN":"ところで、合流することになっていたお二方が、まだお見えになりませんね。","ENG":"By the way, we're missing two guests.","TWN":"但是現在還沒看到準備和您會合的那兩位，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"무슨 일이라도 생긴 건 아니겠죠?","JPN":"何かあったんでしょうか？","ENG":"I wonder if something happened to them...","TWN":"不會是出什麼事了吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"히익! 무, 무슨 소리죠?!!","JPN":"ひっ！　な、何の音ですか！？","ENG":"Heek! Wh-what was that?!","TWN":"啊啊！什、什麼聲音啊？！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_EXPLOSION_ATTACK_BIG_02"},{"id":"L44_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"저쪽! ......이 아니라, 11시 방향에서 신원 불명의 2인을 포착!","JPN":"あっち！　……じゃなくて、11時方向から身元不明の二人組を発見！","ENG":"Look over there! ... I mean, two unidentified individuals at 11 o'clock!","TWN":"這裡！……不是，是11點鐘方向，抓到了兩個身份不明者！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그 뒤로 대규모 침식체 무리가 접근 중이다!","JPN":"その後ろから、大規模な侵食体の群れが接近中！","ENG":"With a horde of C.O. behind them!","TWN":"後方有大規模的侵蝕體正在接近！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"통제권자의 대응방침을 요청하겠다!","JPN":"統制者の対応方針を要請する！","ENG":"Commander, tell me what to do!","TWN":"要求掌權者給出對應方針！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"신원 불명의 2인......? 설마 남은 게스트?","JPN":"身元不明の二人組……？　まさか、残りのゲスト？","ENG":"Two unidentified individuals? Can they be the missing guests?","TWN":"兩個身份不明者……？難道是剩下的嘉賓？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무, 무슨 짓을 한 거야! 소대장!!","JPN":"な、何をしたの！　小隊長！！","ENG":"Wh-what did you do, Commander?!","TWN":"你、你在搞什麼啊！小隊長！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"무슨 짓이라니!","JPN":"何ってなんだ！","ENG":"What do you mean, what did I do?","TWN":"什麼搞什麼啊！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"난 그저 이 한심한 임무를 빨리 끝내려고 했을 뿐이다, 신입!","JPN":"私はただ、このくだらない任務を早く終わらせようとしただけだ、新人！","ENG":"I only tried to get this stupid mission over with, Rookie!","TWN":"我只是想快點結束這個讓人寒心的任務啊，新人！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건 좋아! 좋다고!","JPN":"それは別にいいの！","ENG":"Okay, alright!","TWN":"這很好！我說很好！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_UI_WARFARE_EXPLOSION_BIG"},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 보이는 침식체마다 시비를 걸고 다닐 필요는 없잖아!","JPN":"でもね……だからといって、侵食体に会うたびにケンカ売ってどうするの！？","ENG":"But did you really have to provoke every single C.O. you saw?","TWN":"天天看到侵蝕體就去挑釁，根本沒必要啊！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이래선 임무가 끝나기 전에 우리 인생이 끝날 판이라고!","JPN":"このままじゃ任務が終わる前に、私たちの寿命が縮むよ！","ENG":"We can get over with our lives before the mission!","TWN":"再這樣下去，任務結束前我們就要先完蛋了！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"작전 중에 예상치 못한 사소한 문제가 발생하는 건 흔히 있는 일이지.","JPN":"作戦中に予期せぬ問題が発生するのは、よくあることだ。","ENG":"Unexpected mishaps are not uncommon during operations.","TWN":"超乎預料的小問題，作戰中不是很常出現嘛。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"마침 저기 합류지점이 보이는군, 저기까지만 가면 지원 병력이 기다리고 있을 거다.","JPN":"ちょうど合流地点が見えてきた。\\nあそこに行けば、援護兵が待っているはずだ。","ENG":"Our rally point is in sight. If we just get there, the others can help us.","TWN":"正好能看見那裡的會合地點，只要到那兒就可以等待支援了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 네 말대로 인생이 끝나고 싶지 않다면 빨리 달려!","JPN":"だから寿命を縮ませたくなければ、とにかく全力で走れ！","ENG":"So, if you don't want to lose your life, run!","TWN":"時候還沒到，如果不想完蛋的話，就快跑起來！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다리 움직이는 거 보인다!!","JPN":"もっと早く！！","ENG":"You're not moving fast enough!","TWN":"看見它腿在動！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};